    // INDEXAÇÃO ESPACIAL: Bounding Boxes calculadas uma única vez
    private val ROUTE_BOUNDING_BOXES: Map<String, BoundingBox> by lazy {
        ITAPOA_ROUTES.mapValues { calculateBoundingBox(it.value) }
    }

    private const val TARGET_CITY_RAW = "ITAPOA"

    /**
     * SÊNIOR LOGIC: Extrai a parte do GRUPO do identificador da rota.
     * Ex: "18.7" -> "18"
     */
    fun findSuggestedGroup(cidadeNome: String?, lat: Double?, lng: Double?): String? {
        if (lat == null || lng == null) return null
        
        val normalizedCity = (cidadeNome ?: "").uppercase(java.util.Locale.ROOT)
            .replace("Á", "A").replace("Ã", "A").replace("Õ", "O").trim()
            
        // Se a cidade estiver vazia ou for ITAPOA, permitimos a detecção
        if (normalizedCity.isNotBlank() && !normalizedCity.contains(TARGET_CITY_RAW)) return null

        val fullRoute = findSuggestedRouteId(lat, lng) ?: return null
        return fullRoute.split(".").firstOrNull()
    }

    /**
     * SÊNIOR LOGIC: Extrai a parte da ROTA do identificador da rota.
     * Ex: "18.7" -> "7"
     */
    fun findSuggestedRoute(cidadeNome: String?, lat: Double?, lng: Double?): String? {
        if (lat == null || lng == null) return null
        
        val normalizedCity = (cidadeNome ?: "").uppercase(java.util.Locale.ROOT)
            .replace("Á", "A").replace("Ã", "A").replace("Õ", "O").trim()
            
        if (normalizedCity.isNotBlank() && !normalizedCity.contains(TARGET_CITY_RAW)) return null

        val fullRoute = findSuggestedRouteId(lat, lng) ?: return null
        return fullRoute.split(".").getOrNull(1)
    }

    /**
     * Busca o identificador completo da rota (ex: "18.7") baseado na proximidade.
     */
    private fun findSuggestedRouteId(lat: Double?, lng: Double?): String? {
        if (lat == null || lng == null) return null

        val p = Point(lat, lng)
        
        // 1. ESTRATÉGIA DE ELITE: Ponto em Polígono (Ray Casting)
        // Como o mapa cobre 100% da cidade, o leiturista SEMPRE estará dentro de um polígono.
        for ((routeName, path) in ITAPOA_ROUTES) {
            val bbox = ROUTE_BOUNDING_BOXES[routeName] ?: continue
            if (isPointInBoundingBox(p, bbox)) {
                if (isPointInPolygon(p, path)) {
                    Log.d("GeoHelper", "🎯 SUCESSO: Ponto dentro do Polígono da Rota $routeName")
                    return routeName
                }
            }
        }

        // 2. FALLBACK: Proximidade (Caso o GPS esteja na borda externa de um polígono)
        var bestRoute: String? = null
        var minDistance = Double.MAX_VALUE

        for ((routeName, path) in ITAPOA_ROUTES) {
            val bbox = ROUTE_BOUNDING_BOXES[routeName] ?: continue
            if (!isPointInBoundingBox(p, bbox)) continue

            val dist = minDistanceToPath(p, path)
            if (dist < ROUTE_DETECTION_TOLERANCE_METERS && dist < minDistance) {
                minDistance = dist
                bestRoute = routeName
            }
        }
        
        if (bestRoute != null) {
            Log.d("GeoHelper", "📍 FALLBACK: Ponto por proximidade (${minDistance.toInt()}m) na Rota $bestRoute")
        }
        
        return bestRoute
    }

    /**
     * Algoritmo de Ray Casting: Verifica se um ponto está dentro de um polígono fechado.
     * Crucial para mapas que cobrem áreas totais.
     */
    private fun isPointInPolygon(point: Point, polygon: List<Point>): Boolean {
        var isInside = false
        var j = polygon.size - 1
        for (i in polygon.indices) {
            if (polygon[i].lng > point.lng != polygon[j].lng > point.lng &&
                point.lat < (polygon[j].lat - polygon[i].lat) * (point.lng - polygon[i].lng) / (polygon[j].lng - polygon[i].lng) + polygon[i].lat
            ) {
                isInside = !isInside
            }
            j = i
        }
        return isInside
    }

    private fun minDistanceToPath(point: Point, path: List<Point>): Double {
        var minDest = Double.MAX_VALUE
        for (i in 0 until path.size - 1) {
            val d = distanceToSegment(point, path[i], path[i + 1])
            if (d < minDest) minDest = d
        }
        return minDest
    }

    private fun distanceToSegment(p: Point, a: Point, b: Point): Double {
        val x = (b.lng - a.lng) * cos((a.lat + b.lat) * PI / 360.0)
        val y = b.lat - a.lat
        val lenSq = x * x + y * y
        
        if (lenSq == 0.0) return haversine(p.lat, p.lng, a.lat, a.lng)

        val t = (((p.lng - a.lng) * cos((a.lat + b.lat) * PI / 360.0) * x) + (p.lat - a.lat) * y) / lenSq
        val constrainedT = max(0.0, min(1.0, t))

        val projLat = a.lat + constrainedT * (b.lat - a.lat)
        val projLng = a.lng + constrainedT * (b.lng - a.lng)

        return haversine(p.lat, p.lng, projLat, projLng)
    }

    private fun haversine(lat1: Double, lon1: Double, lat2: Double, lon2: Double): Double {
        val dLat = (lat2 - lat1) * PI / 180.0
        val dLon = (lon2 - lon1) * PI / 180.0
        val a = sin(dLat / 2) * sin(dLat / 2) +
                cos(lat1 * PI / 180.0) * cos(lat2 * PI / 180.0) *
                sin(dLon / 2) * sin(dLon / 2)
        return EARTH_RADIUS_METERS * (2 * atan2(sqrt(a), sqrt(1 - a)))
    }

    private fun calculateBoundingBox(points: List<Point>): BoundingBox {
        var minLat = Double.MAX_VALUE; var maxLat = -Double.MAX_VALUE
        var minLng = Double.MAX_VALUE; var maxLng = -Double.MAX_VALUE
        for (p in points) {
            if (p.lat < minLat) minLat = p.lat
            if (p.lat > maxLat) maxLat = p.lat
            if (p.lng < minLng) minLng = p.lng
            if (p.lng > maxLng) maxLng = p.lng
        }
        return BoundingBox(minLat - 0.0005, maxLat + 0.0005, minLng - 0.0005, maxLng + 0.0005)
    }

    private fun isPointInBoundingBox(p: Point, bbox: BoundingBox): Boolean {
        return p.lat in bbox.minLat..bbox.maxLat && p.lng in bbox.minLng..bbox.maxLng
    }
